ruleSearch.bookList:
class.col-md-3 col-xs-6 mb10 mt10
<js>
result.toArray().slice(0,10).map(o=>{
    var detail = String(o.select('a').attr('href')).replace(/^\//, baseUrl.match(/(.+?\/\/[^\/]+\/)/)[1]);
    var J = org.jsoup.Jsoup.parse(java.ajax(detail));
    var oText = s=>String(o.select(s).text().trim()).replace(/.+：/, '');
    var jText = s=>String(J.select(s).text().trim()).replace(/.+：/, '');
    return {
       name:  oText('strong'),
       author:oText('.text-muted'),
       tags:   J.select('meta[property="og:novel:category"]').attr('content'),
       latest: J.select('meta[property="og:novel:latest_chapter_name"]').attr('content')+ '（' + J.select('meta[property="og:novel:update_time"]').attr('content')+ '）',
       intro: jText('#bookIntro'),
       cover: o.select('img').attr('src'),
       catalogUrl:detail
    }
}).filter(v =>v.name);
</js>
